using TMPro; using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.UI { public class MoveTextUI:MonoBehaviour{ [SerializeField] MoveManager moveManager; [SerializeField] TMP_Text moveText; [SerializeField] string prefix="Moves: "; void Awake(){ moveManager??=FindAnyObjectByType<MoveManager>(); moveText??=GetComponent<TMP_Text>(); } void OnEnable(){ if(moveManager!=null) moveManager.OnMovesChanged+=UpdateText; } void OnDisable(){ if(moveManager!=null) moveManager.OnMovesChanged-=UpdateText; } void Start()=>Refresh(); public void Refresh()=>UpdateText(moveManager?moveManager.RemainingMoves:0); void UpdateText(int moves){ if(moveText!=null) moveText.text=$"{prefix}{moves}"; }} }
